import React, { useState, useEffect, useRef } from "react";
import { X, Mic, MicOff, ShoppingCart, Plus, Trash2, Edit3, ChevronDown, AlertCircle } from "lucide-react";
import { wordsToNumbers } from "words-to-numbers";

// Enhanced product database
const productDatabase = [
  { id: 1, item: "Apple iPhone 15", brand: "Apple", rate: 79900, category: "Electronics" },
  { id: 2, item: "Samsung Galaxy S24", brand: "Samsung", rate: 74999, category: "Electronics" },
  { id: 3, item: "Laptop Dell XPS", brand: "Dell", rate: 89999, category: "Electronics" },
  { id: 4, item: "Wireless Headphones", brand: "Sony", rate: 15999, category: "Electronics" },
  { id: 5, item: "Coffee Beans", brand: "Starbucks", rate: 899, category: "Food" },
  { id: 6, item: "Green Tea", brand: "Twinings", rate: 450, category: "Beverages" },
  { id: 7, item: "Protein Powder", brand: "Optimum", rate: 3500, category: "Health" },
  { id: 8, item: "Running Shoes", brand: "Nike", rate: 8999, category: "Sports" },
];

const knownUnits = ["kg", "g", "liters", "bottles", "packets", "pieces", "dozen", "box", "boxes", "l", "ml", "units", "pair", "pairs"];

// Utility function to detect unit and item
function detectUnit(itemStr) {
  const words = itemStr.trim().toLowerCase().split(/\s+/);
  const firstWord = words[0];
  const lastWord = words[words.length - 1];

  if (knownUnits.includes(firstWord)) {
    return { unit: firstWord, item: words.slice(1).join(" ") };
  }
  if (knownUnits.includes(lastWord)) {
    return { unit: lastWord, item: words.slice(0, -1).join(" ") };
  }
  return { unit: "unit", item: itemStr.trim() };
}

// Utility function to remove prepositions
function removePrepositions(text) {
  const prepositions = ["of", "in", "on", "at", "by", "with", "about", "against", "between", "into", "through", "during", "before", "after", "above", "below", "to", "from", "up", "down", "over", "under"];
  const regex = new RegExp(`\\b(${prepositions.join("|")})\\b`, "gi");
  return text.replace(regex, "").replace(/\s+/g, " ").trim();
}

// Parse multiple orders from transcript
function parseMultipleOrders(transcript) {
  let normalized;
  try {
    transcript = transcript.replace(/[^a-zA-Z0-9\s.,]/g, "").replace(/\s+/g, " ").trim();
    transcript = removePrepositions(transcript);
    normalized = wordsToNumbers(transcript);
  } catch (error) {
    console.error("Error normalizing transcript:", error);
    normalized = transcript;
  }

  const orders = [];
  const regex = /(\d+(?:\.\d+)?)\s+([a-zA-Z][a-zA-Z\s]*?)(?=\s+\d+|$)/g;
  let match;
  while ((match = regex.exec(normalized)) !== null) {
    const [, quantity, itemText] = match;
    const { unit, item } = detectUnit(itemText.trim());
    orders.push({ item, quantity: parseFloat(quantity), unit });
  }
  return orders;
}

const CreateOrder = ({ isOpen, onClose, onAddOrder }) => {
  const [orderData, setOrderData] = useState({ customerName: "", items: [] });
  const [voiceInput, setVoiceInput] = useState({ transcript: "", isListening: false });
  const [manualItem, setManualItem] = useState({ item: "", brand: "", quantity: 1, unit: "pieces", rate: 0 });
  const [errors, setErrors] = useState({});
  const recognitionRef = useRef(null);

  const startVoiceRecognition = () => {
    if (!recognitionRef.current) return;
    recognitionRef.current.start();
  };

  const stopVoiceRecognition = () => {
    if (recognitionRef.current) recognitionRef.current.stop();
    setVoiceInput((prev) => ({ ...prev, isListening: false }));
  };

  const parseVoiceOrder = () => {
    const parsedItems = parseMultipleOrders(voiceInput.transcript);
    const mappedItems = parsedItems.map((parsedItem) => {
      const matchingProduct = productDatabase.find((product) =>
        product.item.toLowerCase().includes(parsedItem.item.toLowerCase())
      );
      return {
        id: Date.now() + Math.random(),
        item: matchingProduct ? matchingProduct.item : parsedItem.item,
        brand: matchingProduct ? matchingProduct.brand : "Unknown Brand",
        quantity: parsedItem.quantity || 1,
        rate: matchingProduct ? matchingProduct.rate : 100,
        unit: parsedItem.unit || "pieces",
        relatedProducts: productDatabase.filter((product) =>
          product.item.toLowerCase().includes(parsedItem.item.toLowerCase())
        ),
      };
    });
    setOrderData((prev) => ({ ...prev, items: [...prev.items, ...mappedItems] }));
    setVoiceInput((prev) => ({ ...prev, transcript: "" }));
  };

  const addManualItem = () => {
    const matchingProduct = productDatabase.find((product) =>
      product.item.toLowerCase().includes(manualItem.item.toLowerCase())
    );
    const newItem = {
      id: Date.now() + Math.random(),
      item: manualItem.item,
      brand: manualItem.brand || (matchingProduct ? matchingProduct.brand : "Custom Brand"),
      quantity: manualItem.quantity,
      rate: manualItem.rate || (matchingProduct ? matchingProduct.rate : 100),
      unit: manualItem.unit,
      relatedProducts: productDatabase.filter((product) =>
        product.item.toLowerCase().includes(manualItem.item.toLowerCase())
      ),
    };
    setOrderData((prev) => ({ ...prev, items: [...prev.items, newItem] }));
    setManualItem({ item: "", brand: "", quantity: 1, unit: "pieces", rate: 0 });
  };

  const removeItem = (itemId) => {
    setOrderData((prev) => ({
      ...prev,
      items: prev.items.filter((item) => item.id !== itemId),
    }));
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 backdrop-blur-sm flex justify-center items-center z-50 p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden">
        <div className="bg-blue-800 text-white p-6 relative">
          <button onClick={onClose} className="absolute top-4 right-4 text-white hover:bg-white hover:bg-opacity-20 rounded-full p-2 transition-colors">
            <X className="w-5 h-5" />
          </button>
          <h2 className="text-2xl font-bold">Create New Order</h2>
        </div>
        <div className="p-6 overflow-y-auto max-h-[calc(90vh-100px)]">
          <div className="mb-6">
            <label className="block text-sm font-medium text-gray-700 mb-2">Customer Name *</label>
            <input
              type="text"
              placeholder="Enter customer name"
              className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-blue-500"
              value={orderData.customerName}
              onChange={(e) => setOrderData((prev) => ({ ...prev, customerName: e.target.value }))}
            />
          </div>
          <div className="mb-6">
            <textarea
              placeholder="Transcript will appear here..."
              className="w-full px-4 py-3 border rounded-lg h-32 resize-none focus:ring-2 focus:ring-blue-500"
              value={voiceInput.transcript}
              onChange={(e) => setVoiceInput((prev) => ({ ...prev, transcript: e.target.value }))}
            />
            <button onClick={parseVoiceOrder} className="bg-blue-500 text-white px-4 py-2 rounded-lg mt-4">
              Parse Order
            </button>
          </div>
          {orderData.items.length > 0 && (
            <div className="mb-6">
              <h3 className="text-lg font-semibold text-gray-800 mb-4">Order Items</h3>
              <ul className="space-y-4">
                {orderData.items.map((item) => (
                  <li key={item.id} className="bg-gray-100 p-4 rounded-lg">
                    <div className="flex justify-between items-center">
                      <span>
                        {item.quantity} × {item.item} ({item.brand})
                      </span>
                      <button onClick={() => removeItem(item.id)} className="text-red-500 hover:text-red-700">
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                    {item.relatedProducts.length > 0 && (
                      <div className="mt-2">
                        <button className="flex items-center text-blue-500 hover:text-blue-700">
                          <ChevronDown className="w-4 h-4 mr-1" />
                          Show Related Products
                        </button>
                        <ul className="mt-2 space-y-2">
                          {item.relatedProducts.map((product) => (
                            <li key={product.id} className="flex justify-between items-center bg-white p-2 rounded-lg shadow">
                              <span>
                                {product.item} ({product.brand})
                              </span>
                              <span>₹{product.rate.toLocaleString()}</span>
                            </li>
                          ))}
                        </ul>
                      </div>
                    )}
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default CreateOrder;
